import React, { useEffect, useMemo, useState } from "react";
import "./PathologyPage.css";

const API =
  (process.env.REACT_APP_API_BASE || "http://localhost:5000/api") + "/public";

/* ===== static data (UNCHANGED) ===== */
const healthCheckups = [];
const healthTests = [];
const fullBodyCheckups = [];

const PathologyPage = () => {
  const [selected, setSelected] = useState(null);
  const [search, setSearch] = useState("");
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [dbTests, setDbTests] = useState([]);

  /* ===== fetch tests ===== */
  useEffect(() => {
    let ok = true;

    (async () => {
      try {
        const res = await fetch(`${API}/tests`);
        const data = await res.json();
        if (ok) setDbTests(Array.isArray(data) ? data : []);
      } catch {
        if (ok) setDbTests([]);
      }
    })();

    return () => {
      ok = false;
    };
  }, []);

  /* ===== normalize DB tests ===== */
  const dbCards = useMemo(
    () =>
      dbTests.map((t) => ({
        id: t._id,
        title: (t.title || t.name || "Test").toLowerCase(),
        displayTitle: t.title || t.name || "Test",
        img: "https://cdn-icons-png.flaticon.com/512/684/684908.png",
        oldPrice: t.oldPrice || t.price || 0,
        price: t.price || 0,
        discount: t.discount ? `${t.discount}% Off` : "",
        tests: t.tests || [],
        description: t.description || "",
      })),
    [dbTests]
  );

  /* ===== ALL ITEMS ===== */
  const allItems = useMemo(
    () => [...healthCheckups, ...healthTests, ...fullBodyCheckups, ...dbCards],
    [dbCards]
  );

  /* ===== STRICT SEARCH FIX ===== */
  const query = search.trim().toLowerCase();

  const filteredItems = useMemo(() => {
    if (!query) return allItems;

    return allItems.filter((item) => {
      const words = item.title.split(/\s+/);
      return words.includes(query);
    });
  }, [query, allItems]);

  return (
    <div className="pathology-page-root">
      <h1 className="page-title">Pathology — Checkups & Tests</h1>

      {/* ===== Search ===== */}
      <div className="search-container">
        <div className="search-bar">
          <input
            type="text"
            placeholder="Search for any test or medicine..."
            value={search}
            onChange={(e) => {
              setSearch(e.target.value);
              setShowSuggestions(true);
            }}
            onFocus={() => setShowSuggestions(true)}
            onBlur={() => setTimeout(() => setShowSuggestions(false), 150)}
          />
          <button>Search</button>
        </div>

        {/* ===== Suggestions ===== */}
        {showSuggestions && query && filteredItems.length > 0 && (
          <div className="suggestion-box">
            {filteredItems.map((item) => (
              <div
                key={item.id}
                className="suggestion-item"
                onClick={() => {
                  setSearch(item.displayTitle);
                  setSelected(item);
                  setShowSuggestions(false);
                }}
              >
                <strong>{item.displayTitle}</strong>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* ===== Results ===== */}
      <div className="cards-row">
        {filteredItems.length ? (
          filteredItems.map((item) => (
            <div
              key={item.id}
              className="card"
              onClick={() => setSelected(item)}
            >
              <img src={item.img} alt="" className="card-img" />
              <div className="card-title">{item.displayTitle}</div>
              <div className="card-sub">
                <span className="card-price">₹{item.price}</span>
                <span className="card-old">₹{item.oldPrice}</span>
                {item.discount && (
                  <span className="card-discount">{item.discount}</span>
                )}
              </div>
            </div>
          ))
        ) : (
          <p className="no-results">No matching results</p>
        )}
      </div>
    </div>
  );
};

export default PathologyPage;
